async function logout(): Promise<void> {
  const response = await secureFetch(getApiUrl("/api/v1/auth/logout"), {
    method: "POST",
    credentials: "include",
  });

  if (!response.ok) {
    throw new Error("Logout failed");
  }
}

export function useAuth() {
  const queryClient = useQueryClient();
  const [isRedirecting, setIsRedirecting] = useState(false);
  const { data: user, isLoading } = useQuery<User | null>({
    queryKey: ["/api/v1/auth/me"],
    queryFn: fetchUser,
    retry: false,
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  const logoutMutation = useMutation({
    mutationFn: logout,
    onSuccess: () => {
      queryClient.setQueryData(["/api/v1/auth/me"], null);
      setIsRedirecting(true);
      // Clear all queries to ensure fresh state on next login
      queryClient.clear();
    },
  });

  const updatePreferencesMutation = useMutation({
    mutationFn: async (data: {
      hasNotifiedTeam?: boolean;
      readNotificationIds?: number[];
    }) => {
      const response = await secureFetch(
        getApiUrl("/api/v1/user/preferences"),
        {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        },
      );
      if (!response.ok) {
        const text = await response.text();
        throw new Error(`Update preferences failed: ${text}`);
      }
      return response.json();
    },
    onSuccess: (updatedData) => {
      queryClient.setQueryData(["/api/v1/auth/me"], (oldUser: any) => {
        if (!oldUser) return null;
        return { ...oldUser, ...updatedData };
      });
    },
  });

  return {
    user,
    isLoading: isLoading || isRedirecting,
    isAuthenticated: !!user,
    logout: logoutMutation.mutate,
    isLoggingOut: logoutMutation.isPending,
    updatePreferences: updatePreferencesMutation.mutateAsync,
    isUpdatingPreferences: updatePreferencesMutation.isPending,
    isRedirecting,
  };
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { api, buildUrl } from "@shared/routes";
import { apiRequest } from "../lib/queryClient";
import type { Node, Edge } from "@xyflow/react";

export * from "../lib/canvas-cache";
import { clearCanvasLocalCache } from "../lib/canvas-cache";

export function useCanvas(workspaceId: number) {
    const queryClient = useQueryClient();
    const url = buildUrl(api.workspaces.getCanvas.path, { id: workspaceId });

    const query = useQuery({
        queryKey: [url],
        queryFn: async () => {
            const res = await apiRequest("GET", url);
            return res.json() as Promise<{ nodes: Node[]; edges: Edge[] }>;
        },
        enabled: !!workspaceId,
    });

    const syncMutation = useMutation({
        mutationFn: async ({ nodes, edges }: { nodes: Node[]; edges: Edge[] }) => {
            // Normalize animated property for Postgres compatibility
            const normalizedEdges = edges.map(edge => ({
                ...edge,
                animated: edge.animated ? 1 : 0
            }));
            const res = await apiRequest("POST", url, { nodes, edges: normalizedEdges });
            return res.json();
        },
        onSuccess: () => {
            clearCanvasLocalCache(workspaceId);
            queryClient.invalidateQueries({ queryKey: [url] });
        },
    });

    return {
        ...query,
        syncAsync: syncMutation.mutateAsync,
        sync: syncMutation.mutate,
        isSyncing: syncMutation.isPending,
    };
}

import { useEffect, useRef, useState, useCallback } from "react";

// ─── Types ───────────────────────────────────────────────────────────

export interface PresenceUser {
  userId: string;
  name: string;
  color: string;
  cursor: { x: number; y: number } | null;
}

interface ServerMessage {
  type: "presence" | "cursor" | "joined" | "left" | "error" | "node-move" | "canvas-sync" | "nodes-change" | "edges-change";
  users?: PresenceUser[];
  userId?: string;
  name?: string;
  color?: string;
  x?: number;
  y?: number;
  message?: string;
  nodeId?: string;
  nodeX?: number;
  nodeY?: number;
  parentId?: string | null;
  nodes?: any[];
  edges?: any[];
  changes?: any[];
}

// ─── Hook ────────────────────────────────────────────────────────────

export function usePresence(
  workspaceId: number | null,
  onNodeMove?: (nodeId: string, x: number, y: number, parentId?: string | null) => void,
  onCanvasSync?: (nodes: any[], edges: any[]) => void,
  onNodesChange?: (changes: any[]) => void,
  onEdgesChange?: (changes: any[]) => void,
) {
  const wsRef = useRef<WebSocket | null>(null);
  const onNodeMoveRef = useRef(onNodeMove);
  onNodeMoveRef.current = onNodeMove;
  const onCanvasSyncRef = useRef(onCanvasSync);
  onCanvasSyncRef.current = onCanvasSync;
  const onNodesChangeRef = useRef(onNodesChange);
  onNodesChangeRef.current = onNodesChange;
  const onEdgesChangeRef = useRef(onEdgesChange);
  onEdgesChangeRef.current = onEdgesChange;
  const [collaborators, setCollaborators] = useState<Map<string, PresenceUser>>(new Map());
  const [isConnected, setIsConnected] = useState(false);
  const reconnectTimer = useRef<ReturnType<typeof setTimeout>>();

  const connect = useCallback(() => {
    if (!workspaceId) return;

    // Build WS URL from current location
    const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
    const host = import.meta.env.VITE_API_URL
      ? new URL(import.meta.env.VITE_API_URL).host
      : window.location.host;
    const url = `${protocol}//${host}/ws`;

    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onopen = () => {
      setIsConnected(true);
      // Authenticate and join the workspace room
      ws.send(JSON.stringify({ type: "join", workspaceId }));
    };

    ws.onmessage = (event) => {
      try {
        const msg: ServerMessage = JSON.parse(event.data);

        switch (msg.type) {
          case "presence": {
            // Full state sync on join
            const map = new Map<string, PresenceUser>();
            for (const user of msg.users || []) {
              map.set(user.userId, user);
            }
            setCollaborators(map);
            break;
          }

          case "joined": {
            if (msg.userId && msg.name && msg.color) {
              setCollaborators((prev) => {
                const next = new Map(prev);
                next.set(msg.userId!, {
                  userId: msg.userId!,
                  name: msg.name!,
                  color: msg.color!,
                  cursor: null,
                });
                return next;
              });
            }
            break;
          }

          case "cursor": {
            if (msg.userId) {
              setCollaborators((prev) => {
                const next = new Map(prev);
                const existing = next.get(msg.userId!);
                if (existing) {
                  next.set(msg.userId!, {
                    ...existing,
                    cursor: { x: msg.x || 0, y: msg.y || 0 },
                  });
                }
                return next;
              });
            }
            break;
          }

          case "left": {
            if (msg.userId) {
              setCollaborators((prev) => {
                const next = new Map(prev);
                next.delete(msg.userId!);
                return next;
              });
            }
            break;
          }

          case "error": {
            console.warn("[Presence] Server error:", msg.message);
            break;
          }

          case "node-move": {
            if (msg.nodeId != null && msg.nodeX != null && msg.nodeY != null) {
              onNodeMoveRef.current?.(msg.nodeId, msg.nodeX, msg.nodeY, msg.parentId);
            }
            break;
          }

          case "canvas-sync": {
            if (msg.nodes && msg.edges) {
              onCanvasSyncRef.current?.(msg.nodes, msg.edges);
            }
            break;
          }

          case "nodes-change": {
            if (msg.changes) {
              onNodesChangeRef.current?.(msg.changes);
            }
            break;
          }

          case "edges-change": {
            if (msg.changes) {
              onEdgesChangeRef.current?.(msg.changes);
            }
            break;
          }
        }
      } catch {
        // Ignore malformed messages
      }
    };

    ws.onclose = () => {
      setIsConnected(false);
      wsRef.current = null;
      // Reconnect after 3 seconds
      reconnectTimer.current = setTimeout(() => connect(), 3000);
    };

    ws.onerror = () => {
      ws.close();
    };
  }, [workspaceId]);

  // Connect on mount, disconnect on unmount
  useEffect(() => {
    connect();

    return () => {
      clearTimeout(reconnectTimer.current);
      if (wsRef.current) {
        wsRef.current.send(JSON.stringify({ type: "leave" }));
        wsRef.current.close();
        wsRef.current = null;
      }
      setCollaborators(new Map());
      setIsConnected(false);
    };
  }, [connect]);

  // Send cursor position (throttled by caller)
  const sendCursor = useCallback((x: number, y: number) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: "cursor", x, y }));
    }
  }, []);

  const sendNodeMove = useCallback((nodeId: string, x: number, y: number, parentId?: string | null) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: "node-move", nodeId, nodeX: x, nodeY: y, parentId: parentId ?? null }));
    }
  }, []);

  const sendCanvasSync = useCallback((nodes: any[], edges: any[]) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: "canvas-sync", nodes, edges }));
    }
  }, []);

  const sendNodesChange = useCallback((changes: any[]) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: "nodes-change", changes }));
    }
  }, []);

  const sendEdgesChange = useCallback((changes: any[]) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: "edges-change", changes }));
    }
  }, []);

  return {
    collaborators: Array.from(collaborators.values()),
    isConnected,
    sendCursor,
    sendNodeMove,
    sendCanvasSync,
    sendNodesChange,
    sendEdgesChange,
  };
}

