export const CANVAS_CACHE_PREFIX = "meshwork-canvas-cache-";

export interface CanvasCache {
    nodes: any[];
    edges: any[];
    timestamp: number;
}

export function saveCanvasToLocalCache(workspaceId: number, nodes: any[], edges: any[]) {
    try {
        const cache: CanvasCache = { nodes, edges, timestamp: Date.now() };
        localStorage.setItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`, JSON.stringify(cache));
    } catch (e) {
        console.warn("Failed to save canvas to local cache", e);
    }
}

export function getCanvasFromLocalCache(workspaceId: number): CanvasCache | null {
    try {
        const item = localStorage.getItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`);
        return item ? JSON.parse(item) : null;
    } catch (e) {
        console.warn("Failed to read canvas from local cache", e);
        return null;
    }
}

export function clearCanvasLocalCache(workspaceId: number) {
    localStorage.removeItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`);
}

import { useEffect } from "react";
import { storeCsrfToken } from "./secure-fetch";

/**
 * Initialize CSRF token on app load
 * Should be called once in App.tsx or a layout component
 */
export function useCsrfTokenInitializer() {
  useEffect(() => {
    // Fetch CSRF token on mount
    const initializeCsrfToken = async () => {
      try {
        const response = await fetch("/api/v1/csrf-token", {
          credentials: "include",
        });
        if (response.ok) {
          const data = await response.json();
          if (data.csrfToken) {
            storeCsrfToken(data.csrfToken);
          }
        }
      } catch (error) {
        console.error("[CSRF] Failed to initialize token:", error);
        // Continue anyway - token will be fetched on first use if needed
      }
    };

    initializeCsrfToken();
  }, []);
}

import { QueryClient, QueryFunction } from "@tanstack/react-query";
import { secureFetch } from "./secure-fetch";

const API_BASE_URL = import.meta.env.VITE_API_URL || "";

function getApiUrl(path: string): string {
  if (path.startsWith("http")) return path;
  return `${API_BASE_URL}${path}`;
}

async function throwIfResNotOk(res: Response) {
  if (!res.ok) {
    const text = (await res.text()) || res.statusText;
    throw new Error(`${res.status}: ${text}`);
  }
}

export async function apiRequest(
  method: string,
  url: string,
  data?: unknown,
): Promise<Response> {
  const res = await secureFetch(getApiUrl(url), {
    method,
    headers: data ? { "Content-Type": "application/json" } : {},
    body: data ? JSON.stringify(data) : undefined,
    credentials: "include",
  });

  await throwIfResNotOk(res);
  return res;
}

type UnauthorizedBehavior = "returnNull" | "throw";
export const getQueryFn: <T>(options: {
  on401: UnauthorizedBehavior;
}) => QueryFunction<T> =
  ({ on401: unauthorizedBehavior }) =>
  async ({ queryKey }) => {
    const res = await fetch(getApiUrl(queryKey.join("/")), {
      credentials: "include",
    });

    if (unauthorizedBehavior === "returnNull" && res.status === 401) {
      return null;
    }

    await throwIfResNotOk(res);
    return await res.json();
  };

export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      queryFn: getQueryFn({ on401: "throw" }),
      refetchInterval: false,
      refetchOnWindowFocus: false,
      staleTime: Infinity,
      retry: false,
    },
    mutations: {
      retry: false,
    },
  },
});

import { useQueryClient } from "@tanstack/react-query";

/**
 * Helper to get CSRF token from query cache
 */
function getCsrfTokenFromCache(): string {
  try {
    const queryClient = useQueryClient();
    return queryClient.getQueryData(["csrf-token"])! || "";
  } catch {
    return "";
  }
}

/**
 * Enhanced fetch function that automatically includes CSRF token
 *
 * This wraps the native fetch API to automatically add:
 * - X-CSRF-Token header for state-changing requests
 * - Proper error handling
 *
 * Usage is identical to fetch():
 * ```tsx
 * const response = await secureFetch('/api/v1/auth/register', {
 *   method: 'POST',
 *   body: JSON.stringify(data),
 * });
 * ```
 */
export async function secureFetch(
  input: RequestInfo | URL,
  init?: RequestInit,
): Promise<Response> {
  const method = (init?.method || "GET").toUpperCase();

  // Only add CSRF token for state-changing requests
  if (!["GET", "HEAD", "OPTIONS"].includes(method)) {
    const csrfToken = getCsrfToken();

    // Initialize headers if not present
    if (!init) {
      init = {};
    }
    if (!init.headers) {
      init.headers = {};
    }

    // Ensure headers is a plain object (can be HeadersInit)
    const headers = new Headers(init.headers);

    // Add CSRF token
    if (csrfToken) {
      headers.set("X-CSRF-Token", csrfToken);
    }

    init.headers = headers;
  }

  let response = await fetch(input, init);

  // Automatic JWT Token Refresh
  // If the request fails with 401 and it's not the refresh endpoint itself,
  // we try to use the refresh_token cookie to get a new access_token cookie.
  const urlString = input.toString();
  if (
    response.status === 401 &&
    !urlString.includes("/api/v1/auth/refresh") &&
    !urlString.includes("/api/v1/auth/login") &&
    !urlString.includes("/api/v1/auth/logout")
  ) {
    try {
      const refreshResponse = await fetch("/api/v1/auth/refresh", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        // Required to send and receive the HttpOnly cookies
        credentials: "include",
      });

      if (refreshResponse.ok) {
        // Refresh succeeded, the new access_token cookie is now set.
        // Retry the original request!
        response = await fetch(input, init);
      }
    } catch (refreshErr) {
      console.warn("Token refresh failed:", refreshErr);
    }
  }

  return response;
}

/**
 * Get CSRF token from sessionStorage
 */
function getCsrfToken(): string {
  if (typeof window !== "undefined") {
    const stored = sessionStorage.getItem("csrfToken");
    if (stored) {
      return stored;
    }
  }
  return "";
}

/**
 * Store CSRF token in session storage
 */
export function storeCsrfToken(token: string): void {
  if (typeof window !== "undefined") {
    sessionStorage.setItem("csrfToken", token);
  }
}

/**
 * Clear CSRF token
 */
export function clearCsrfToken(): void {
  if (typeof window !== "undefined") {
    sessionStorage.removeItem("csrfToken");
  }
}

