      "https://www.google.com",
      "https://recaptcha.google.com",
    ],
    "connect-src": [
      "'self'",
      frontendUrl,
      "https://www.google.com",
      "https://www.gstatic.com",
    ],
    "img-src": [
      "'self'",
      "data:",
      "https://www.gstatic.com",
      "https://*.googleusercontent.com",
      "https://lh3.googleusercontent.com",
      "https://lh4.googleusercontent.com",
      "https://lh5.googleusercontent.com",
    ],
    "style-src": ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com"],
    "font-src": ["'self'", "https://fonts.gstatic.com", "data:"],
  },
};

if (process.env.NODE_ENV === "production") {
  app.use(
    helmet({
      contentSecurityPolicy: cspConfig,
    }),
  );
} else {
  app.use(
    helmet({
      contentSecurityPolicy: {
        directives: {
          ...cspConfig.directives,
          "script-src": [
            "'self'",
            "'unsafe-inline'",
            "localhost",
            "https://www.google.com",
            "https://www.gstatic.com",
          ],
          "connect-src": [
            "'self'",
            "localhost:*",
            "ws://localhost:*",
            "https://www.google.com",
            "https://www.gstatic.com",
          ],
        },
      },
    }),
  );
}

// CORS configuration (for all environments)
if (frontendUrl) {
  app.use(
    cors({
      origin: frontendUrl,
      credentials: true,
      methods: ["GET", "POST", "PUT", "DELETE", "OPTIONS"],
      allowedHeaders: ["Content-Type", "Authorization", "X-CSRF-Token"],
    }),
  );
} else if (process.env.NODE_ENV !== "production") {
  app.use(cors({ origin: true, credentials: true }));
}

// API Versioning Compatibility Layer
app.use((req, res, next) => {
  if (req.url.startsWith("/api/") && !req.url.startsWith("/api/v1/")) {
    req.url = req.url.replace("/api/", "/api/v1/");
  }
  next();
});

// SECURITY: Add request size limits to prevent DoS
app.use(
  express.json({
    limit: "5mb",
    verify: (req, _res, buf) => {
      req.rawBody = buf;
    },
  }),
);

app.use(express.urlencoded({ extended: false, limit: "5mb" }));

// Prometheus metrics middleware
app.use(metricsMiddleware);

// SECURITY: CSRF Protection - Setup cookie parser before CSRF middleware
app.use(cookieParser());

// Note: CSRF protection is applied per-route in auth routes,
// not globally, because it needs session middleware to be initialized first.
// Session middleware is initialized by setupAuth() in registerRoutes()

// Real Health Check endpoint
app.get("/health", async (_req, res) => {
  try {
    const checks = {
      postgres: false,
      redis: false,
    };

    // Check Postgres
    try {
      await db.execute(sql`SELECT 1`);
      checks.postgres = true;
    } catch (err) {
      log.error({ err }, "Postgres health check failed");
    }

    // Check Redis
    checks.redis = await isRedisAvailable();

    const isHealthy =
      checks.postgres && (!process.env.REDIS_URL || checks.redis);
    const status = isHealthy ? "healthy" : "degraded";
    const statusCode = isHealthy ? 200 : 503;

    res.status(statusCode).json({
      status,
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
      memory: process.memoryUsage(),
      checks,
    });
  } catch (err) {
    log.error({ err }, "Health check endpoint error");
    res
      .status(500)
      .json({ status: "error", message: "Internal health check error" });
  }
});

// Readiness Probe
app.get("/ready", (_req, res) => {
  if (isAppReady) {
    res
      .status(200)
      .json({ status: "ready", timestamp: new Date().toISOString() });
  } else {
    res.status(503).json({ status: "not_ready" });
  }
});

// Prometheus Metrics Endpoint
app.get("/metrics", async (_req, res) => {
  try {
    res.set("Content-Type", metricsRegistry.contentType);
    const metrics = await metricsRegistry.metrics();
    res.send(metrics);
  } catch (err) {
    log.error({ err }, "Metrics endpoint error");
    res.status(500).send("Error generating metrics");
  }
});

// Admin Metrics Dashboard — secret URL, never exposed in logs/sitemaps
const adminSecret = process.env.ADMIN_SECRET || "";
app.get("/admin/:secret", (req, res) => {
  if (!adminSecret || req.params.secret !== adminSecret) {
    return res.status(404).send("Not Found");
  }
  try {
    const htmlPath = path.resolve(__dirname, "admin.html");
    // eslint-disable-next-line security/detect-non-literal-fs-filename
    if (fs.existsSync(htmlPath)) {
      // eslint-disable-next-line security/detect-non-literal-fs-filename
      res.type("html").send(fs.readFileSync(htmlPath, "utf-8"));
    } else {
      res.status(404).send("Admin dashboard not found");
    }
  } catch (err) {
    res.status(500).send("Error loading dashboard");
  }
});

(async () => {
  const port = parseInt(process.env.PORT || "5000", 10);

  // Start listening BEFORE expensive initialization to pass healthchecks early.
  // Port 0.0.0.0 is required for Railway/Docker.
  httpServer.listen(port, "0.0.0.0", () => {
    log.info(
      `Server started listening on port ${port} (initializing modules...)`,
    );
  });

  try {
    log.info("Starting database migrations...");
    try {
      await db.execute(
        sql`ALTER TABLE workspaces ADD COLUMN IF NOT EXISTS updated_at timestamp DEFAULT CURRENT_TIMESTAMP`,
      );
      await db.execute(
        sql`UPDATE workspaces SET updated_at = created_at WHERE updated_at > '2026-04-19 07:00:00' AND updated_at < '2026-04-19 08:30:00' AND created_at < '2026-04-19 07:00:00'`,
      );
      log.info("Database migrations applied successfully");
    } catch (dbErr) {
      log.warn(
        { err: dbErr },
        "Failed to apply DB migrations, might already exist or DB is unavailable",
      );
    }

    log.info("Starting module initialization...");
    await registerRoutes(httpServer, app);
    log.info("All modules initialized successfully");

    // Initialize WebSocket presence server for real-time cursors
    const { initializeWebSocket } = await import("./modules/team/websocket");
    initializeWebSocket(httpServer);
    log.info("WebSocket presence server initialized");

    // Importantly only setup vite in development and after
    // setting up all the other routes so the catch-all route
    // doesn't interfere with the other routes
    if (process.env.NODE_ENV !== "production") {
      const { setupVite } = await import("./vite");
      await setupVite(httpServer, app);
    }

    // Global error handler — MUST be registered AFTER all routes
    app.use((err: any, _req: Request, res: Response, next: NextFunction) => {
      const status = err.status || err.statusCode || 500;

      log.error({ err, status }, "Unhandled error reached global handler");

      if (res.headersSent) {
        return next(err);
      }

      // Handle Postgres database constraint errors
      if (err.code === "23505") {
        return res.status(400).json({
          message:
            "A record with this value already exists. Please use a unique value.",
        });
      }
      if (err.code === "23503") {
        return res.status(400).json({
          message: "Referenced record does not exist or cannot be deleted.",
        });
      }
      if (err.code === "22P02") {
        return res
          .status(400)
          .json({ message: "Invalid data format provided." });
      }

      // SECURITY: Never forward raw error messages to clients in production
      const clientMessage =
        process.env.NODE_ENV === "production"
          ? "An unexpected error occurred"
          : err.message || "Internal Server Error";

      return res.status(status).json({ message: clientMessage });
    });

    isAppReady = true;
    log.info(`Server fully ready and serving on port ${port}`);
  } catch (error) {
    console.error("CRITICAL FAILURE:", error);
    log.fatal({ err: error }, "CRITICAL FAILURE DURING SERVER INITIALIZATION");
    log.error(
      "The server is still listening on /health but other routes may be broken.",
    );
  }

  // Serve static files LAST so the SPA catch-all doesn't swallow API routes.
  // Runs outside the try/catch so frontend always loads even if modules fail.
  if (process.env.NODE_ENV === "production") {
    log.info("Serving static frontend files from /public");
    serveStatic(app);
  }
})();

import pino from "pino";

/**
 * Structured logger for Meshwork Studio.
 *
 * - Development: pretty-printed, colorized output via pino-pretty
 * - Production: raw JSON lines (machine-parseable for log aggregators)
 *
 * Usage:
 *   import { logger, createChildLogger } from "./lib/logger";
 *   const log = createChildLogger("auth");
 *   log.info("User logged in", { userId: "abc" });
 */

const isProduction = process.env.NODE_ENV === "production";

export const logger = pino({
  level: process.env.LOG_LEVEL || (isProduction ? "info" : "debug"),
  ...(isProduction
    ? {}
    : {
        transport: {
          target: "pino-pretty",
          options: {
            colorize: true,
            translateTime: "HH:MM:ss",
            ignore: "pid,hostname",
          },
        },
      }),
});

/**
 * Create a child logger scoped to a specific module.
 * All log lines from this child will include `{ module: "<name>" }`.
 *
 * @example
 * const log = createChildLogger("websocket");
 * log.info("Client connected", { workspaceId: 42 });
 * // => { level: "info", module: "websocket", msg: "Client connected", workspaceId: 42 }
 */
export function createChildLogger(module: string) {
  return logger.child({ module });
}

import Redis from "ioredis";
import type { Redis as RedisType } from "ioredis";
import { createChildLogger } from "./logger";

// ─── Singleton Redis Client ─────────────────────────────────────────
// Used for sessions, caching, and general key-value operations.
// For pub/sub, use createRedisClient() to get a dedicated connection.

const log = createChildLogger("redis");

let redis: RedisType | null = null;
let redisAvailable = false;

function getRedisUrl(): string | null {
  const url = process.env.REDIS_URL;
  // Allow explicit disable with empty string
  if (url === "") return null;
  return url || "redis://localhost:6379";
}

/**
 * Get the singleton Redis client.
 * Lazily connects on first call. Returns null if Redis is not configured
 * or unavailable (allows graceful degradation in development).
 */
export function getRedis(): RedisType | null {
  if (redis) return redis;

  const url = getRedisUrl();
  if (!url) {
    log.info("Redis disabled (REDIS_URL empty)");
    return null;
  }

  try {
    redis = new Redis(url, {
      maxRetriesPerRequest: 3,
      retryStrategy(times) {
        if (times > 5) {
          log.warn("Max reconnection attempts reached, giving up");
          return null; // Stop retrying
        }
        return Math.min(times * 200, 2000); // Exponential backoff, max 2s
      },
      lazyConnect: true,
    });

    redis.on("connect", () => {
      redisAvailable = true;
      log.info("Connected successfully");
    });

    redis.on("error", (err) => {
      redisAvailable = false;
      if (redis?.status === "connecting") {
        log.warn({ err: err.message }, "Connection failed");
      }
    });

    redis.on("close", () => {
      redisAvailable = false;
    });

    // Attempt connection (non-blocking)
    redis.connect().catch((err) => {
      log.warn({ err: err.message }, "Initial connection failed (degrading gracefully)");
      redisAvailable = false;
    });

    return redis;
  } catch (err: any) {
    log.warn({ err: err.message }, "Failed to create client");
    return null;
  }
}

/**
 * Create a new, independent Redis connection.
 * Required for pub/sub (ioredis enters subscriber mode on the connection,
 * blocking it from other commands).
 */
export function createRedisClient(): RedisType | null {
  try {
    const url = getRedisUrl();
    if (!url) return null;

    const client = new Redis(url, {
      maxRetriesPerRequest: 3,
      retryStrategy(times) {
        if (times > 5) return null;
        return Math.min(times * 200, 2000);
      },
    });
    return client;
  } catch (err: any) {
    log.warn({ err: err.message }, "Failed to create pub/sub client");
    return null;
  }
}

/**
 * Check if Redis is currently connected and responsive.
 * Used by the health check endpoint.
 */
export async function isRedisAvailable(): Promise<boolean> {
  if (!redis || !redisAvailable) return false;
  try {
    const pong = await redis.ping();
    return pong === "PONG";
  } catch {
    return false;
  }
}

/**
 * Gracefully disconnect the singleton Redis client.
 * Call during server shutdown.
 */
export async function disconnectRedis(): Promise<void> {
  if (redis) {
    await redis.quit();
    redis = null;
    redisAvailable = false;
  }
}

