import type { Request, Response, NextFunction } from "express";

export class AppRegistry {
  private services = new Map<string, any>();

  register<T>(name: string, service: T): void {
    if (this.services.has(name)) {
      throw new Error(`Service ${name} is already registered`);
    }
    this.services.set(name, service);
  }

  get<T>(name: string): T {
    const service = this.services.get(name);
    if (!service) {
      throw new Error(`Service ${name} not found in registry`);
    }
    return service as T;
  }
}

export interface AppContext {
  registry: AppRegistry;
  eventBus: typeof import('./events').eventBus;
}

import type { Request, Response, NextFunction } from "express";
import csrf from "csurf";
import { createChildLogger } from "../lib/logger";

const log = createChildLogger("csrf");

declare global {
  namespace Express {
    interface Request {
      csrfToken(): string;
    }
  }
}

/**
 * CSRF Protection Middleware
 *
 * Uses double-submit cookie pattern for CSRF protection.
 * The token should be:
 * 1. Generated for each session
 * 2. Sent to client in response header
 * 3. Sent back by client in request header or body for state-changing operations
 */

// Initialize CSRF protection with cookie-based storage
const _csrfMiddleware = csrf({
  cookie: {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "strict",
  },
});

/**
 * CSRF middleware — skipped when E2E_BYPASS_AUTH=true so Playwright tests can
 * make mutating API calls without needing to pre-seed a csurf cookie.
 */
export const csrfProtection: import("express").RequestHandler = (
  req,
  res,
  next,
) => {
  if (process.env.E2E_BYPASS_AUTH === "true") {
    return next();
  }
  return _csrfMiddleware(req, res, next);
};

/**
 * Middleware to generate CSRF token
 * This should be called on the initial page load or login
 */
export const generateCsrfToken = (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  // Generate token and attach to response header
  const token =
    typeof req.csrfToken === "function" ? req.csrfToken() : "mock-csrf-token";
  res.set("X-CSRF-Token", token);
  next();
};

/**
 * Middleware to validate CSRF token on state-changing operations
 * Checks for token in:
 * 1. X-CSRF-Token header (preferred for APIs)
 * 2. _csrf body field (for form submissions)
 */
export const validateCsrfToken = (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  // Skip CSRF check for GET/HEAD/OPTIONS (idempotent methods)
  if (["GET", "HEAD", "OPTIONS"].includes(req.method)) {
    return next();
  }

  // Skip CSRF check for public auth endpoints (handled specially)
  if (req.path === "/api/auth/register" || req.path === "/api/auth/login") {
    return next();
  }

  csrfProtection(req, res, (err: any) => {
    if (err) {
      // CSRF token validation failed
      log.warn(
        { method: req.method, path: req.path, error: err.message },
        "Token validation failed",
      );
      return res.status(403).json({
        message: "CSRF validation failed",
        error: process.env.NODE_ENV === "production" ? undefined : err.message,
      });
    }
    next();
  });
};

/**
 * Helper to get CSRF token from request
 * Used internally to verify token presence
 */
export const getCsrfToken = (req: Request): string | null => {
  return req.get("X-CSRF-Token") || req.body?._csrf || null;
};

import type { Request, Response, NextFunction } from "express";
import { httpRequestsTotal, httpRequestDurationSeconds } from "../lib/metrics";

export function metricsMiddleware(req: Request, res: Response, next: NextFunction) {
  // Ignore the metrics and health endpoints to prevent noise
  if (req.path === "/metrics" || req.path === "/health" || req.path === "/ready") {
    return next();
  }

  const start = process.hrtime();

  res.on("finish", () => {
    const duration = process.hrtime(start);
    const durationInSeconds = duration[0] + duration[1] / 1e9;

    // Use a simplified path for metrics to avoid high cardinality
    // E.g. /api/workspace/123 -> /api/workspace/:id
    let path = req.route ? req.baseUrl + req.route.path : req.path;

    if (!path || path === "/") path = "root";

    httpRequestsTotal.labels(req.method, path, res.statusCode.toString()).inc();
    httpRequestDurationSeconds.labels(req.method, path).observe(durationInSeconds);
  });

  next();
}

import rateLimit from "express-rate-limit";

// Global API rate limiter - protects against general DoS
// Limit each IP to 100 requests per 1 minute window
export const apiLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 100, // Limit each IP to 100 requests per window
  message: {
    message: "Too many requests from this IP, please try again after a minute.",
  },
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
  skip: () => process.env.NODE_ENV === "test",
});

// Strict authentication rate limiter - protects against credential stuffing
// Limit each IP to 10 requests per 15 minute window
export const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // Limit each IP to 10 requests per window
  message: {
    message:
      "Too many authentication attempts, please try again after 15 minutes.",
  },
  standardHeaders: true,
  legacyHeaders: false,
  skip: () => process.env.NODE_ENV === "test",
});

// Refresh token rate limiter - prevents token farming
// Limit each IP to 100 requests per 1 hour window
export const refreshLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 100, // Limit each IP to 100 refresh requests per window
  message: {
    message: "Too many token refresh requests, please try again later.",
  },
  standardHeaders: true,
  legacyHeaders: false,
  skip: () => process.env.NODE_ENV === "test",
});

// AI chat rate limiter - prevents cost exfiltration via unmetered proxy
// Limit each IP to 30 requests per 1 minute window
export const aiChatLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 30, // Limit each IP to 30 AI requests per window
  message: { message: "Too many AI requests, please slow down." },
  standardHeaders: true,
  legacyHeaders: false,
  skip: () => process.env.NODE_ENV === "test",
});

// Tighter rate limiter for free-tier AI requests (app-owned key).
// BYOK users spend their own money; free-tier spends ours — cap it harder.
// Applied conditionally by the route handler after provider resolution.
export const aiFreeTierLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 10, // 10 req/min on free tier (vs 30 for BYOK)
  message: {
    message:
      "Free tier rate limit reached. Add your own API key in settings for higher limits.",
  },
  standardHeaders: true,
  legacyHeaders: false,
  skip: () => process.env.NODE_ENV === "test",
  keyGenerator: (req: any) => {
    // Key by user ID (not IP) so per-user limits are accurate.
    // This middleware only runs behind isAuthenticated, so req.user is always set.
    return req.user?.id ?? "anonymous";
  },
});

import type { Request, Response, NextFunction } from "express";
import { ZodSchema, ZodError } from "zod";

interface ValidationSchemas {
  body?: ZodSchema;
  query?: ZodSchema;
  params?: ZodSchema;
}

export function validate(schemas: ValidationSchemas) {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      if (schemas.body) {
        req.body = schemas.body.parse(req.body);
      }
      if (schemas.query) {
        req.query = schemas.query.parse(req.query);
      }
      if (schemas.params) {
        req.params = schemas.params.parse(req.params);
      }
      next();
    } catch (error) {
      if (error instanceof ZodError) {
        const errors = error.errors.map((err) => ({
          field: err.path.join("."),
          message: err.message,
        }));

        // Find the first informative message to show at the top level
        const firstError = errors[0];
        const defaultMessage = firstError ? `${firstError.field}: ${firstError.message}` : "Validation failed";

        return res.status(400).json({
          message: defaultMessage,
          errors,
        });
      }
      next(error);
    }
  };
}

import { eq, and, desc } from "drizzle-orm";
import { drizzle } from "drizzle-orm/node-postgres";
import pg from "pg";
import { createChildLogger } from "../../lib/logger";

const log = createChildLogger("ai-db");
import * as schema from "@shared/schema";
import { encryptApiKey, decryptApiKey, generateKeyHint } from "./encryption";

import { type NodePgDatabase } from "drizzle-orm/node-postgres";
import { type DrizzleTx } from "../../lib/events";

const { Pool } = pg;

const connectionString = process.env.DATABASE_URL;

if (!connectionString) {
  log.error(
    "DATABASE_URL not set. AI module will fall back to placeholder mode.",
  );
}

let db: NodePgDatabase<typeof schema>;
if (connectionString) {
  const pool = new Pool({ connectionString });
  db = drizzle(pool, { schema });
} else {
  // Placeholder db for development without database
  db = {
    select: () => ({
      from: () => ({ where: () => ({ limit: () => Promise.resolve([]) }) }),
    }),
    insert: () => ({ values: () => Promise.resolve([]) }),
    update: () => ({ set: () => ({ where: () => Promise.resolve({}) }) }),
    delete: () => ({ from: () => ({ where: () => Promise.resolve({}) }) }),
    transaction: (callback: any) => callback(db),
  } as unknown as NodePgDatabase<typeof schema>;
}

export { db };

// Types from schema
export type UserApiKey = typeof schema.userApiKeys.$inferSelect;
export type InsertUserApiKey = typeof schema.userApiKeys.$inferInsert;

/**
 * Database operations for user API keys
 * All keys are encrypted before storage and only decrypted when needed
 */

export interface CreateKeyInput {
  userId: string;
  provider: string;
  apiKey: string;
}

export interface KeyWithPlaintext extends UserApiKey {
  plaintextKey: string;
}

/**
 * Create a new encrypted API key for a user
 */
export async function createApiKey(input: CreateKeyInput): Promise<UserApiKey> {
  // Encrypt the API key
  const { encryptedData, iv, authTag } = encryptApiKey(input.apiKey);

  // Generate hint for UI
  const keyHint = generateKeyHint(input.apiKey);

  // Wrap in a transaction: deactivate any existing active key for this
  // user+provider BEFORE inserting the new one. This closes the race window
  // where two concurrent "add key" requests could both land as active.
  // The partial unique index in the schema is the belt; this is the suspenders.
  return await db.transaction(async (tx: DrizzleTx) => {
    // Deactivate existing active key(s) for this user+provider
    await tx
      .update(schema.userApiKeys)
      .set({ isActive: false, updatedAt: new Date() })
      .where(
        and(
          eq(schema.userApiKeys.userId, input.userId),
          eq(schema.userApiKeys.provider, input.provider),
          eq(schema.userApiKeys.isActive, true),
        ),
      );

    const [result] = await tx
      .insert(schema.userApiKeys)
      .values({
        userId: input.userId,
        provider: input.provider,
        encryptedKey: encryptedData,
        iv,
        authTag,
        keyHint,
        isActive: true,
      })
      .returning();

    return result;
  });
}

/**
 * Get all API keys for a user (without plaintext - safe for UI)
 */
export async function getUserApiKeys(userId: string): Promise<UserApiKey[]> {
  return await db
    .select()
    .from(schema.userApiKeys)
    .where(eq(schema.userApiKeys.userId, userId))
    .orderBy(schema.userApiKeys.createdAt);
}

/**
 * Get active API keys for a user by provider
 * Returns encrypted data - must be decrypted before use
 */
export async function getActiveKeyForProvider(
  userId: string,
  provider: string,
): Promise<UserApiKey | null> {
  const [result] = await db
    .select()
    .from(schema.userApiKeys)
    .where(
      and(
        eq(schema.userApiKeys.userId, userId),
        eq(schema.userApiKeys.provider, provider),
        eq(schema.userApiKeys.isActive, true),
      ),
    )
    .orderBy(desc(schema.userApiKeys.createdAt))
    .limit(1);

  return result || null;
}

/**
 * Get a specific API key with decrypted plaintext
 * Use sparingly - only when making actual API calls
 */
export async function getApiKeyWithPlaintext(
  userId: string,
  keyId: string,
): Promise<KeyWithPlaintext | null> {
  const [result] = await db
    .select()
    .from(schema.userApiKeys)
    .where(
      and(
        eq(schema.userApiKeys.id, keyId),
        eq(schema.userApiKeys.userId, userId),
      ),
    )
    .limit(1);

  if (!result) {
    return null;
  }

  // Decrypt the key
  const plaintextKey = decryptApiKey(
    result.encryptedKey,
    result.iv,
    result.authTag,
  );

  return {
    ...result,
    plaintextKey,
  };
}

/**
 * Delete an API key
 */
export async function deleteApiKey(
  userId: string,
  keyId: string,
): Promise<boolean> {
  const result = await db
    .delete(schema.userApiKeys)
    .where(
      and(
        eq(schema.userApiKeys.id, keyId),
        eq(schema.userApiKeys.userId, userId),
      ),
    )
    .returning();

  return result.length > 0;
}

/**
 * Toggle key active status
 */
export async function toggleKeyStatus(
  userId: string,
  keyId: string,
  isActive: boolean,
): Promise<UserApiKey | null> {
  const [result] = await db
    .update(schema.userApiKeys)
    .set({ isActive, updatedAt: new Date() })
    .where(
      and(
        eq(schema.userApiKeys.id, keyId),
        eq(schema.userApiKeys.userId, userId),
      ),
    )
    .returning();

  return result || null;
}

/**
 * Check if user has any keys for a provider
 */
export async function hasKeyForProvider(
  userId: string,
  provider: string,
): Promise<boolean> {
  const result = await db
    .select({ count: schema.userApiKeys.id })
    .from(schema.userApiKeys)
    .where(
      and(
        eq(schema.userApiKeys.userId, userId),
        eq(schema.userApiKeys.provider, provider),
        eq(schema.userApiKeys.isActive, true),
      ),
    )
    .limit(1);

  return result.length > 0;
}

