// ---------------------------------------------------------------------------
// Error mapping — ProviderResolutionError → HTTP response
// ---------------------------------------------------------------------------

function handleResolutionError(error: ProviderResolutionError, res: Response) {
  switch (error.code) {
    case "BYOK_DECRYPT_FAILED":
      return res.status(500).json({ code: error.code, message: error.message });
    case "NO_ACTIVE_KEY":
      return res.status(404).json({ code: error.code, message: error.message });
    case "FALLBACK_NOT_CONFIGURED":
      return res.status(503).json({ code: error.code, message: error.message });
    default:
      return res.status(500).json({ message: error.message });
  }
}

export default function createAIRoutes(context: AppContext) {
  const router = Router();
  const isAuthenticated = context.registry.get<RequestHandler>("isAuthenticated");

  // CSRF is active in production by default; set ENABLE_CSRF=true in .env to test locally
  const csrfEnabled =
    process.env.ENABLE_CSRF === "true" || process.env.NODE_ENV === "production";
  const conditionalCsrf = csrfEnabled
    ? csrfProtection
    : (_req: Request, _res: Response, next: () => void) => next();

  /**
   * GET /api/ai/keys
   * List all API keys for the current user (returns hints only, never full keys)
   */
  router.get("/keys", isAuthenticated, async (req: Request, res: Response) => {
    try {
      const userId = req.user!.id;
      const keys = await getUserApiKeys(userId);

      // Return keys without encrypted data
      res.json(
        keys.map((key) => ({
          id: key.id,
          provider: key.provider,
          keyHint: key.keyHint,
          isActive: key.isActive,
          createdAt: key.createdAt,
        })),
      );
    } catch (error) {
      log.error({ err: error, userId: req.user?.id }, "Failed to list keys");
      res.status(500).json({ message: "Failed to retrieve API keys" });
    }
  });

  /**
   * POST /api/ai/keys
   * Add a new API key (encrypted and stored)
   * Uses transactional deactivate-then-insert to prevent duplicate active keys.
   */
  router.post(
    "/keys",
    isAuthenticated,
    conditionalCsrf,
    async (req: Request, res: Response) => {
      try {
        const userId = req.user!.id;
        const { provider, apiKey } = req.body;

        // Validate input
        if (!provider || !apiKey) {
          return res
            .status(400)
            .json({ message: "Provider and apiKey are required" });
        }

        // Validate key format
        if (!validateKeyFormat(provider, apiKey)) {
          return res.status(400).json({
            message: `Invalid API key format for ${provider}`,
          });
        }

        // Create encrypted key (deactivates previous key in a transaction)
        const key = await createApiKey({ userId, provider, apiKey });

        res.status(201).json({
          id: key.id,
          provider: key.provider,
          keyHint: key.keyHint,
          isActive: key.isActive,
          createdAt: key.createdAt,
        });
      } catch (error) {
        log.error(
          { err: error, userId: req.user?.id, provider: req.body?.provider },
          "Failed to create key",
        );
        res.status(500).json({ message: "Failed to store API key" });
      }
    },
  );

  /**
   * POST /api/ai/keys/test
   * Test an API key without storing it
   */
  router.post(
    "/keys/test",
    isAuthenticated,
    async (req: Request, res: Response) => {
      try {
        const { provider, apiKey } = req.body;

        if (!provider || !apiKey) {
          return res
            .status(400)
            .json({ message: "Provider and apiKey are required" });
        }

        // Validate format
        if (!validateKeyFormat(provider, apiKey)) {
          return res.status(400).json({
            message: `Invalid API key format for ${provider}`,
          });
        }

        // Validate the key against the actual provider API
        let valid = false;
        let validationError = "";

        try {
          if (provider === "openai") {
            const { validateOpenAIKey } = await import("./providers/openai");
            valid = await validateOpenAIKey(apiKey);
          } else if (provider === "anthropic") {
            const { validateAnthropicKey } =
              await import("./providers/anthropic");
            valid = await validateAnthropicKey(apiKey);
          } else if (provider === "openrouter") {
            const { validateOpenRouterKey } =
              await import("./providers/openrouter");
            valid = await validateOpenRouterKey(apiKey);
          } else {
            return res
              .status(400)
              .json({ message: `Unsupported provider: ${provider}` });
          }
        } catch (validationErr: unknown) {
          log.error(
            { err: validationErr, provider },
            "Key validation call failed",
          );
          validationError = "Could not reach provider to validate key";
        }

        if (!valid && !validationError) {
          validationError = `API key is not valid for ${provider}`;
        }

        res.json({
          valid,
          message: valid ? "API key is valid and working" : validationError,
        });
      } catch (error) {
        log.error(
          { err: error, provider: req.body?.provider },
          "Failed to test key",
        );
        res.status(500).json({ message: "Failed to test API key" });
      }
    },
  );

  /**
   * DELETE /api/ai/keys/:id
   * Delete an API key
   */
  router.delete(
    "/keys/:id",
    isAuthenticated,
    conditionalCsrf,
    async (req: Request, res: Response) => {
      try {
        const userId = req.user!.id;
        const keyId = req.params.id as string;

        const deleted = await deleteApiKey(userId, keyId);

        if (!deleted) {
          return res.status(404).json({ message: "API key not found" });
        }

        res.json({ success: true });
      } catch (error) {
        log.error(
          { err: error, userId: req.user?.id, keyId: req.params.id },
          "Failed to delete key",
        );
        res.status(500).json({ message: "Failed to delete API key" });
      }
    },
  );

  /**
   * POST /api/ai/chat
   * Proxy chat completion request to AI provider.
   *
   * Uses resolveProviderForRequest() as the single decision point:
   * - If provider is omitted or is the default → free-tier fallback (env key)
   * - If provider is a BYOK provider → user's stored key
   * - Failures are specific (BYOK_DECRYPT_FAILED, NO_ACTIVE_KEY, etc.)
   */
  router.post(
    "/chat",
    isAuthenticated,
    conditionalCsrf,
    aiChatLimiter,
    async (req: Request, res: Response) => {
      try {
        const userId = req.user!.id;
        const { provider, model, messages, temperature, maxTokens, stream } =
          req.body as {
            provider?: string;
            model?: string;
            messages: Array<{ role: "user" | "assistant" | "system"; content: string }>;
            temperature?: number;
            maxTokens?: number;
            stream?: boolean;
          };

        // messages is always required; provider and model are optional
        // (omitting them triggers the free-tier fallback).
        if (!messages || !Array.isArray(messages)) {
          return res
            .status(400)
            .json({ message: "messages array is required" });
        }

        const start = process.hrtime();

        // ---------------------------------------------------------------
        // Resolve provider — the ONE decision point
        // ---------------------------------------------------------------
        let resolved;
        try {
          resolved = await resolveProviderForRequest(userId, provider, model);
        } catch (error) {
          if (error instanceof ProviderResolutionError) {
            return handleResolutionError(error, res);
          }
          throw error;
        }

        // Apply tighter rate limit for free-tier requests (app's money)
        if (resolved.source === "fallback") {
          const freeTierAllowed = await new Promise<boolean>((resolve) => {
            aiFreeTierLimiter(req, res, (err?: unknown) => {
              if (err) {
                resolve(false);
              } else {
                resolve(!res.headersSent);
              }
            });
          });
          if (!freeTierAllowed || res.headersSent) return;
        }

        res.on("finish", () => {
          const duration = process.hrtime(start);
          const durationInSeconds = duration[0] + duration[1] / 1e9;
          const status = res.statusCode >= 400 ? "error" : "success";

          aiChatRequestsTotal
            .labels(resolved.provider, resolved.model, status)
            .inc();
          aiChatDurationSeconds
            .labels(resolved.provider)
            .observe(durationInSeconds);
        });

        const apiKey = resolved.apiKey;
        const resolvedProvider = resolved.provider;
        const resolvedModel = resolved.model;

        log.info(
          {
            userId,
            provider: resolvedProvider,
            model: resolvedModel,
            source: resolved.source,
          },
          "Chat request resolved",
        );

        // Route to appropriate provider
        if (resolvedProvider === "openai") {
          const { createOpenAIChatCompletion } =
            await import("./providers/openai");

          if (stream) {
            res.setHeader("Content-Type", "text/event-stream");
            res.setHeader("Cache-Control", "no-cache");
            res.setHeader("Connection", "keep-alive");

            const { streamOpenAIChatCompletion } =
              await import("./providers/openai");
            const sseStream = streamOpenAIChatCompletion(apiKey, {
              model: resolvedModel,
              messages,
              temperature,
              maxTokens,
              stream: true,
            });

            for await (const chunk of sseStream) {
              res.write(`data: ${JSON.stringify({ content: chunk })}\n\n`);
            }

            res.write("data: [DONE]\n\n");
            res.end();
          } else {
            const response = await createOpenAIChatCompletion(apiKey, {
              model: resolvedModel,
              messages,
              temperature,
              maxTokens,
              stream: false,
            });
            res.json(response);
          }
        } else if (resolvedProvider === "anthropic") {
          const {
            createAnthropicChatCompletion,
            streamAnthropicChatCompletion,
          } = await import("./providers/anthropic");

          if (stream) {
            res.setHeader("Content-Type", "text/event-stream");
            res.setHeader("Cache-Control", "no-cache");
            res.setHeader("Connection", "keep-alive");

            const sseStream = streamAnthropicChatCompletion(apiKey, {
              model: resolvedModel,
              messages,
              temperature,
              maxTokens,
              stream: true,
            });

            for await (const chunk of sseStream) {
              res.write(`data: ${JSON.stringify({ content: chunk })}\n\n`);
            }

            res.write("data: [DONE]\n\n");
            res.end();
          } else {
            const response = await createAnthropicChatCompletion(apiKey, {
              model: resolvedModel,
              messages,
              temperature,
              maxTokens,
              stream: false,
            });

            const data = await response.json();
            res.json(data);
          }
        } else if (resolvedProvider === "openrouter") {
          const {
            createOpenRouterChatCompletion,
            streamOpenRouterChatCompletion,
          } = await import("./providers/openrouter");

          if (stream) {
            res.setHeader("Content-Type", "text/event-stream");
            res.setHeader("Cache-Control", "no-cache");
            res.setHeader("Connection", "keep-alive");

            const sseStream = streamOpenRouterChatCompletion(apiKey, {
              model: resolvedModel,
              messages,
              temperature,
              maxTokens,
              stream: true,
            });

            for await (const chunk of sseStream) {
              res.write(`data: ${JSON.stringify({ content: chunk })}\n\n`);
            }

            res.write("data: [DONE]\n\n");
            res.end();
          } else {
            const response = await createOpenRouterChatCompletion(apiKey, {
              model: resolvedModel,
              messages,
              temperature,
              maxTokens,
              stream: false,
            });
            res.json(response);
          }
        } else {
          return res
            .status(400)
            .json({ message: `Unsupported provider: ${resolvedProvider}` });
        }
      } catch (error: unknown) {
        log.error(
          {
            err: error,
            userId: req.user?.id,
          },
          "Chat completion failed",
        );

        // Pass through upstream provider errors with useful context
        const providerError = error as { status?: number; statusCode?: number; message?: string };
        const statusCode = providerError.status ?? providerError.statusCode ?? 502;
        const message = providerError.message ?? "AI provider returned an error";
        res
          .status(statusCode >= 400 && statusCode < 600 ? statusCode : 502)
          .json({
            code: "PROVIDER_ERROR",
            message,
          });
      }
    },
  );

  /**
   * POST /api/ai/suggestions
   * Generate contextual next-step suggestions based on the current canvas state.
   * Uses the same resolver as /chat — no independent key-lookup logic.
   */
  router.post(
    "/suggestions",
    isAuthenticated,
    conditionalCsrf,
    async (req: Request, res: Response) => {
      try {
        const userId = req.user!.id;
        const { canvas } = req.body as { canvas?: { nodes?: Node[]; edges?: Edge[] } }; // { nodes, edges }

        // Resolve provider — use free tier by default for suggestions
        let resolved;
        try {
          resolved = await resolveProviderForRequest(
            userId,
            undefined,
            undefined,
          );
        } catch (error) {
          if (error instanceof ProviderResolutionError) {
            // If we can't resolve any provider, return static fallback suggestions
            return res.json([
              "Design a scalable Kubernetes microservices architecture",
              "Set up a high-availability Postgres cluster",
              "Build a serverless event-driven data pipeline",
              "Create a secure AWS VPC with public/private subnets",
            ]);
          }
          throw error;
        }

        const { provider, apiKey } = resolved;

        // Select a lightweight model for suggestions (cheaper than full chat)
        let suggestionsModel: string;
        if (provider === "openai") {
          suggestionsModel = "gpt-4o-mini";
        } else if (provider === "anthropic") {
          suggestionsModel = "claude-3-5-haiku-20241022";
        } else if (provider === "openrouter") {
          suggestionsModel = "meta-llama/llama-3-8b-instruct:free";
        } else {
          return res.status(400).json({
            message: `Unsupported provider for suggestions: ${provider}`,
          });
        }

        const canvasNodes: Node[] = canvas?.nodes ?? [];
        const canvasEdges: Edge[] = canvas?.edges ?? [];

        const prompt = `You are Mosh, the expert cloud architecture co-pilot for Meshwork Studio. 
Based on the current canvas state, generate 4 short, highly relevant, and actionable next-step suggestions or starter layout ideas for the user.

Current canvas contains:
- Nodes: ${JSON.stringify(canvasNodes.map((n) => ({ id: n.id, type: n.type, label: (n.data as Record<string, unknown>)?.label ?? n.type })))}
- Edges: ${JSON.stringify(canvasEdges.map((e) => ({ source: e.source, target: e.target })))}

Each suggestion MUST be extremely short (under 6 words).
Provide suggestions that represent logical additions, connections, security settings, or best practices for the current nodes.
If the canvas is empty, provide 4 starter template ideas (e.g. "Create a VPC with Subnets", "Deploy a microservice cluster", "Set up a serverless pipeline", "Design a 3-tier web app").

You MUST return ONLY a valid JSON array of strings, e.g.:
["Add a Redis cache", "Connect Gateway to Backend", "Set up VPC subnets", "Add a load balancer"]

Do NOT wrap the output in markdown code blocks like \`\`\`json. Return only the raw JSON.`;

        let responseText = "";

        if (provider === "openrouter") {
          const { createOpenRouterChatCompletion } =
            await import("./providers/openrouter");
          const response = (await createOpenRouterChatCompletion(apiKey, {
            model: suggestionsModel,
            messages: [{ role: "user", content: prompt }],
            temperature: 0.5,
            maxTokens: 200,
            stream: false,
          })) as ChatCompletionResponse;
          responseText = response.choices?.[0]?.message?.content ?? "";
        } else if (provider === "openai") {
          const { createOpenAIChatCompletion } =
            await import("./providers/openai");
          const response = (await createOpenAIChatCompletion(apiKey, {
            model: suggestionsModel,
            messages: [{ role: "user", content: prompt }],
            temperature: 0.5,
            maxTokens: 200,
            stream: false,
          })) as ChatCompletionResponse;
          responseText = response.choices?.[0]?.message?.content ?? "";
        } else if (provider === "anthropic") {
          const { createAnthropicChatCompletion } =
            await import("./providers/anthropic");
          const response = await createAnthropicChatCompletion(apiKey, {
            model: suggestionsModel,
            messages: [{ role: "user", content: prompt }],
            temperature: 0.5,
            maxTokens: 200,
            stream: false,
          });
          const data = await response.json();
          responseText = data.content?.[0]?.text || "";
        }

        // Parse the response
        responseText = responseText.trim();

        // Clean up code blocks if the LLM returned them despite instructions
        const jsonMatch = /^(?:```(?:json)?\n)?([\s\S]*?)(?:\n```)?$/.exec(
          responseText,
        );
        if (jsonMatch) {
          responseText = jsonMatch[1].trim();
        }

        try {
          const suggestions = JSON.parse(responseText);
          if (Array.isArray(suggestions)) {
            return res.json(suggestions.slice(0, 4));
          }
          throw new Error("Response was not a JSON array");
        } catch (e) {
          log.warn(
            { response: responseText, err: e },
            "Failed to parse suggestions response",
          );
          return res
            .status(502)
            .json({ message: "AI provider returned an unparseable response" });
        }
      } catch (error: unknown) {
        log.error({ err: error, userId: req.user?.id }, "Suggestions failed");
        res.status(500).json({ message: "Suggestions generation failed" });
      }
    },
  );

  /**
   * GET /api/ai/providers
   * List supported AI providers.
   * Marks the default free-tier provider and only lists providers with
   * working adapter files.
   */
  router.get(
    "/providers",
    isAuthenticated,
    async (_req: Request, res: Response) => {
      res.json([
        {
          id: "openai",
          name: "OpenAI",
          models: ["gpt-4", "gpt-4-turbo", "gpt-3.5-turbo"],
          requiresByok: true,
        },
        {
          id: "anthropic",
          name: "Anthropic",
          models: ["claude-3-5-sonnet", "claude-3-opus"],
          requiresByok: true,
        },
        {
          id: "openrouter",
          name: "OpenRouter",
          models: [
            "openai/gpt-oss-120b:free",
            "meta-llama/llama-3-8b-instruct:free",
            "google/gemini-2.5-flash:free",
          ],
          requiresByok: false,
          isDefault: true,
        },
      ]);
    },
  );

  return router;
}

import passport from "passport";
import { createChildLogger } from "../../lib/logger";
import session from "express-session";
import type { Express, RequestHandler } from "express";
import RedisStore from "connect-redis";
import memorystore from "memorystore";
import { getRedis } from "../../lib/redis";
import { createGoogleStrategy } from "./strategies/google";
import { createLocalStrategy } from "./strategies/local";
import { verifyToken } from "./jwt";

const log = createChildLogger("auth");

const getSession = () => {
  const sessionTtl = 7 * 24 * 60 * 60 * 1000; // 1 week
  const connectionString =
    process.env.AUTH_DATABASE_URL || process.env.DATABASE_URL;

  // SECURITY: Require SESSION_SECRET in production - fallback to temporary secret if missing to avoid healthcheck crash
  if (!process.env.SESSION_SECRET) {
    log.error("CRITICAL: SESSION_SECRET environment variable is missing!");
    if (process.env.NODE_ENV === "production") {
      log.error(
        "Using emergency fallback secret. SESSIONS WILL NOT BE SECURE UNTIL FIXED.",
      );
    }
  }

  const redisClient = getRedis();

  if (!redisClient) {
    log.warn(
      "Redis client not available, falling back to in-memory session store (development only)",
    );
    const MemoryStore = memorystore(session);
    return session({
      secret: process.env.SESSION_SECRET || "dev_only_insecure_dev_key_12345",
      resave: false,
      saveUninitialized: false,
      store: new MemoryStore({
        checkPeriod: 86400000,
      }),
      cookie: { secure: false },
    });
  }

  const sessionStore = new RedisStore({
    client: redisClient,
    prefix: "sess:",
    ttl: sessionTtl / 1000, // connect-redis uses seconds for ttl, not ms
  });

  return session({
    secret:
      process.env.SESSION_SECRET ||
      // eslint-disable-next-line no-secrets/no-secrets
      "emergency_fallback_secret_not_real_production_key_12345",
    store: sessionStore,
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      // 'lax' is required for OAuth — 'strict' blocks the session cookie on
      // the redirect back from Google, so Passport can never log the user in
      sameSite: "lax",
      maxAge: sessionTtl,
    },
  });
};

export async function setupAuth(app: Express) {
  app.set("trust proxy", 1);
  app.use(getSession());
  app.use(passport.initialize());
  app.use(passport.session());

  passport.serializeUser((user: Express.User, cb) => cb(null, user));
  passport.deserializeUser((user: Express.User, cb) => cb(null, user));

  // Register Google strategy if configured
  const googleStrategy = createGoogleStrategy();
  if (googleStrategy) {
    passport.use("google", googleStrategy);
  }

  // Register Local strategy
  passport.use("local", createLocalStrategy());
}

export const isAuthenticated: RequestHandler = (req, res, next) => {
  // E2E Test Auth Bypass — allow mock dashboard/canvas testing without active session cookie
  if (process.env.E2E_BYPASS_AUTH === "true") {
    req.user = {
      id: "mock-id-1",
      email: "architect@meshwork.dev",
      firstName: "Test",
      lastName: "User",
      profileImageUrl: null,
      authProvider: "local",
      hasNotifiedTeam: false,
      readNotificationIds: [],
      createdAt: new Date(),
    } as any;
    return next();
  }

  // First check if the user is authenticated via Passport session (useful during transition/OAuth)
  if (req.isAuthenticated && req.isAuthenticated()) {
    return next();
  }

  // Then check for JWT access token in cookies
  const accessToken = req.cookies?.access_token;
  if (!accessToken) {
    return res.status(401).json({ message: "No access token provided" });
  }

  const payload = verifyToken(accessToken, "access");
  if (!payload) {
    return res.status(401).json({ message: "Access token expired or invalid" });
  }

  // Map the JWT payload to req.user so downstream handlers work seamlessly
  req.user = { id: payload.userId } as any;
  next();
};

/**
 * Production-grade CAPTCHA verification utility
 * Supports hCaptcha and reCAPTCHA with security best practices
 */

import { createChildLogger } from "../../lib/logger";
import type { Request, Response, NextFunction } from "express";

const log = createChildLogger("captcha");

interface CaptchaConfig {
  secretKey: string;
  provider: "hcaptcha" | "recaptcha";
  // Score threshold for reCAPTCHA v3 (0.0 to 1.0)
  scoreThreshold?: number;
}

// Track used tokens to prevent replay attacks (in production, use Redis)
const usedTokens = new Set<string>();
const tokenTimestamps = new Map<string, number>();

// Token expiration: 5 minutes
const TOKEN_EXPIRY_MS = 5 * 60 * 1000;

// Cleanup old tokens every 10 minutes
setInterval(
  () => {
    const now = Date.now();
    Array.from(tokenTimestamps.entries()).forEach(([token, timestamp]) => {
      if (now - timestamp > TOKEN_EXPIRY_MS) {
        usedTokens.delete(token);
        tokenTimestamps.delete(token);
      }
    });
  },
  10 * 60 * 1000,
);

function getCaptchaConfig(): CaptchaConfig | null {
  const hcaptchaSecret = process.env.HCAPTCHA_SECRET;
  const recaptchaSecret = process.env.RECAPTCHA_SECRET;
  const scoreThreshold = parseFloat(
    process.env.RECAPTCHA_SCORE_THRESHOLD || "0.5",
  );

  if (hcaptchaSecret) {
    return { secretKey: hcaptchaSecret, provider: "hcaptcha" };
  }

  if (recaptchaSecret) {
    return {
      secretKey: recaptchaSecret,
      provider: "recaptcha",
      scoreThreshold,
    };
  }

  return null;
}

interface CaptchaVerificationResult {
  success: boolean;
  error?: string;
  score?: number;
}

/**
 * Verify a CAPTCHA token with production-grade security
 */
export async function verifyCaptcha(
  token: string,
  remoteIp?: string,
): Promise<CaptchaVerificationResult> {
  const config = getCaptchaConfig();

  // If no CAPTCHA configured, skip verification (dev mode only)
  if (!config) {
    log.debug("No CAPTCHA configured, skipping verification (dev mode)");
    return { success: true };
  }

  // Validate token format (prevent injection)
  if (
    !token ||
    typeof token !== "string" ||
    token.length < 10 ||
    token.length > 2000
  ) {
    log.warn("Invalid token format");
    return { success: false, error: "Invalid CAPTCHA token format" };
  }

  // Check for replay attacks
  if (usedTokens.has(token)) {
    log.warn("Token reuse detected (possible replay attack)");
    return {
      success: false,
      error: "CAPTCHA already used - please complete a new challenge",
    };
  }

  try {
    const verifyUrl =
      config.provider === "hcaptcha"
        ? "https://hcaptcha.com/siteverify"
        : "https://www.google.com/recaptcha/api/siteverify";

    const bodyParams: Record<string, string> = {
      secret: config.secretKey,
      response: token,
    };

    // Include remote IP if available (helps prevent token theft/replay)
    if (remoteIp) {
      bodyParams.remoteip = remoteIp;
    }

    const response = await fetch(verifyUrl, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams(bodyParams),
    });

    if (!response.ok) {
      log.error({ status: response.status }, "Verification service error");
      return {
        success: false,
        error: "CAPTCHA verification service unavailable",
      };
    }

    const data = await response.json() as {
      success: boolean;
      score?: number;
      "error-codes"?: string[];
    };

    if (data.success) {
      // For reCAPTCHA v3, check score
      if (config.provider === "recaptcha" && data.score !== undefined) {
        const threshold = config.scoreThreshold || 0.5;
        if (data.score !== undefined && data.score < threshold) {
          log.warn({ score: data.score, threshold }, "Score too low");
          return {
            success: false,
            error: "CAPTCHA verification failed - suspicious activity detected",
            score: data.score,
          };
        }
        log.debug(
          { score: data.score, provider: config.provider },
          "Passed with score",
        );
      } else {
        log.debug({ provider: config.provider }, "Verification passed");
      }

      // Mark token as used (prevent replay)
      usedTokens.add(token);
      tokenTimestamps.set(token, Date.now());

      return { success: true, score: data.score };
    } else {
      const errorCodes = data["error-codes"] ?? [];
      log.warn(
        { provider: config.provider, errorCodes },
        "Verification failed",
      );

      // Map error codes to user-friendly messages
      const errorMessage = mapErrorCodes(errorCodes, config.provider);
      return { success: false, error: errorMessage };
    }
  } catch (err) {
    log.error({ err }, "Verification error");
    return {
      success: false,
      error: "CAPTCHA verification failed - please try again",
    };
  }
}

function mapErrorCodes(errorCodes: string[], provider: string): string {
  const codeMap: Record<string, string> = {
    "missing-input-secret": "CAPTCHA configuration error",
    "invalid-input-secret": "CAPTCHA configuration error",
    "missing-input-response": "Please complete the CAPTCHA challenge",
    "invalid-input-response": "CAPTCHA response invalid - please try again",
    "bad-request": "Invalid CAPTCHA request",
    "timeout-or-duplicate": "CAPTCHA expired - please complete a new challenge",
  };

  for (const code of errorCodes) {
    if (codeMap[code]) {
      return codeMap[code];
    }
  }

  return "CAPTCHA verification failed - please try again";
}

/**
 * Middleware to verify CAPTCHA token from request body
 * Production-grade with proper error handling
 */
export function captchaMiddleware(req: Request, res: Response, next: NextFunction) {
  const token = req.body.captchaToken;
  const remoteIp =
    req.ip ?? req.socket.remoteAddress ?? (req.headers["x-forwarded-for"] as string | undefined);

  if (!token) {
    return res.status(400).json({
      message:
        "CAPTCHA verification required - please complete the security challenge",
    });
  }

  verifyCaptcha(token, remoteIp)
    .then((result) => {
      if (result.success) {
        // Attach score to request for potential additional checks
        (req as Request & { captchaScore?: number }).captchaScore = result.score;
        next();
      } else {
        res.status(400).json({
          message:
            result.error || "CAPTCHA verification failed - please try again",
        });
      }
    })
    .catch((err) => {
      log.error({ err }, "Middleware error");
      res.status(500).json({
        message: "CAPTCHA verification error - please try again later",
      });
    });
}

/**
 * Skip CAPTCHA middleware for development/testing
 * Use environment variable to control
 */
export function optionalCaptchaMiddleware(req: Request, res: Response, next: NextFunction) {
  // Only enforce CAPTCHA if keys are configured.
  // This allows the user to enable/disable CAPTCHA by simply adding/removing the env var.
  const config = getCaptchaConfig();

  if (!config) {
    log.debug("Skipping verification (no CAPTCHA keys configured)");
    return next();
  }

  // Otherwise use full verification
  return captchaMiddleware(req, res, next);
}

import { drizzle } from "drizzle-orm/node-postgres";
import pg from "pg";
import * as schema from "@shared/schema";
import { createChildLogger } from "../../lib/logger";

const log = createChildLogger("auth-db");

const { Pool } = pg;

const connectionString =
  process.env.AUTH_DATABASE_URL || process.env.DATABASE_URL;

if (!connectionString) {
  log.warn(
    "AUTH_DATABASE_URL not set, falling back to in-memory mode if configured",
  );
}

export const pool = new Pool({
  connectionString: connectionString || "postgres://",
});
export const db = drizzle(pool, { schema });

// Create tables if they don't exist
async function createTables() {
  if (!connectionString) return;

  try {
    // Enable pgcrypto for gen_random_uuid()
    await pool.query(`CREATE EXTENSION IF NOT EXISTS pgcrypto;`);

    // Create users table with new auth fields
    await pool.query(`
            CREATE TABLE IF NOT EXISTS users (
                id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
                email VARCHAR UNIQUE NOT NULL,
                first_name VARCHAR,
                last_name VARCHAR,
                profile_image_url VARCHAR,
                password_hash VARCHAR,
                auth_provider VARCHAR NOT NULL DEFAULT 'email',
                has_notified_team BOOLEAN DEFAULT false,
                read_notification_ids JSONB DEFAULT '[]'::jsonb,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );
        `);
    log.info("Users table created/verified");

    // Session storage has been moved to Redis!

    // Create login_attempts table for account lockout protection
    // eslint-disable-next-line no-secrets/no-secrets
    await pool.query(`
            CREATE TABLE IF NOT EXISTS login_attempts (
                id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
                email VARCHAR NOT NULL,
                failed INTEGER NOT NULL DEFAULT 0,
                last_attempt TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
                locked_until TIMESTAMP,
                created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
            );

            CREATE INDEX IF NOT EXISTS IDX_login_attempts_email ON login_attempts(email);
            CREATE INDEX IF NOT EXISTS IDX_login_attempts_locked_until ON login_attempts(locked_until);
        `);
    log.info("Login attempts table created/verified");
  } catch (err) {
    log.error({ err }, "Failed to create tables");
  }
}

// Safe column migrations — ADD COLUMN IF NOT EXISTS is idempotent, never drops data
async function runMigrations() {
  if (!connectionString) return;

  try {
    // v1.1: Add notification preference columns to users
    await pool.query(`
            ALTER TABLE users ADD COLUMN IF NOT EXISTS has_notified_team BOOLEAN DEFAULT false;
            ALTER TABLE users ADD COLUMN IF NOT EXISTS read_notification_ids JSONB DEFAULT '[]'::jsonb;
        `);
    log.info("Migrations verified (notification preferences)");
  } catch (err) {
    log.error({ err }, "Migration failed");
  }
}

createTables().then(() => runMigrations());

