    const payload = verifyToken(refreshToken, 'refresh');
    expect(payload).not.toBeNull();
    expect(payload!.userId).toBe('user-123');
    expect(payload!.type).toBe('refresh');
  });

  it('should_reject_access_token_when_expect_refresh', () => {
