    clearCanvasLocalCache,
    CANVAS_CACHE_PREFIX 
} from '@/lib/canvas-cache';
// type imports removed to circumvent test runner plugin crash

describe('Canvas Caching Utilities (Unit)', () => {
    let mockStorage: Record<string, string> = {};

    beforeEach(() => {
        mockStorage = {};
        vi.stubGlobal('localStorage', {
            getItem: vi.fn((key: string) => mockStorage[key] || null),
            setItem: vi.fn((key: string, value: string) => { mockStorage[key] = value; }),
            removeItem: vi.fn((key: string) => { delete mockStorage[key]; }),
            clear: vi.fn(() => { mockStorage = {}; })
        });
        vi.clearAllMocks();
    });

    it('should save canvas data to local storage with a timestamp', () => {
        const workspaceId = 1;
        const nodes: any[] = [{ id: 'test-node', position: {x: 0, y: 0}, data: { label: 'Test' } }];
        const edges: any[] = [{ id: 'test-edge', source: 'a', target: 'b' }];

        saveCanvasToLocalCache(workspaceId, nodes, edges);

        const savedData = localStorage.getItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`);
        expect(savedData).not.toBeNull();

        const parsed = JSON.parse(savedData!);
        expect(parsed.nodes).toEqual(nodes);
        expect(parsed.edges).toEqual(edges);
        expect(parsed.timestamp).toBeTypeOf('number');
    });

    it('should retrieve correctly parsed canvas data from local storage', () => {
        const workspaceId = 2;
        const mockData = {
            nodes: [{ id: 'test', position: {x: 0, y: 0}, data: {} }],
            edges: [],
            timestamp: Date.now()
        };

        localStorage.setItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`, JSON.stringify(mockData));

        const retrieved = getCanvasFromLocalCache(workspaceId);
        expect(retrieved).toEqual(mockData);
    });

    it('should return null if there is no cache for the workspace ID', () => {
        const retrieved = getCanvasFromLocalCache(999);
        expect(retrieved).toBeNull();
    });

    it('should clear only the specific workspace cache from localStorage', () => {
        const workspaceId = 3;
        const mockData = { nodes: [], edges: [], timestamp: 123 };

        localStorage.setItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`, JSON.stringify(mockData));
        localStorage.setItem(`${CANVAS_CACHE_PREFIX}999`, JSON.stringify(mockData)); // Another workspace cache

        clearCanvasLocalCache(workspaceId);

        // Workspace 3 should map to null
        expect(localStorage.getItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`)).toBeNull();
        // Workspace 999 should remain untouched
        expect(localStorage.getItem(`${CANVAS_CACHE_PREFIX}999`)).not.toBeNull();
    });

    it('should handle corrupt JSON gracefully by returning null', () => {
        const workspaceId = 4;
        // Seed corrupt JSON
        localStorage.setItem(`${CANVAS_CACHE_PREFIX}${workspaceId}`, "i-am-not-valid-json");

        const warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});

        const retrieved = getCanvasFromLocalCache(workspaceId);

        // Assert it returns null and triggers console.warn instead of crashing the app
        expect(retrieved).toBeNull();
        expect(warnSpy).toHaveBeenCalledWith("Failed to read canvas from local cache", expect.any(Error));

        warnSpy.mockRestore();
    });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { canvasJsonSchema, importFromJson, exportAsJson } from '@/features/workspace/utils/exportCanvas';

// ─── canvasJsonSchema ────────────────────────────────────────────────

describe('canvasJsonSchema', () => {
    const validPayload = {
        title: 'My Canvas',
        nodes: [
            { id: 'n1', type: 'system', position: { x: 100, y: 200 }, data: { label: 'API' } },
            { id: 'n2', position: { x: 300, y: 400 }, data: {} },
        ],
        edges: [
            { id: 'e1', source: 'n1', target: 'n2' },
        ],
        exportedAt: '2026-05-10T12:00:00.000Z',
        version: 1,
    };

    it('accepts a valid canvas payload', () => {
        expect(canvasJsonSchema.safeParse(validPayload).success).toBe(true);
    });

    it('accepts payload without version (optional)', () => {
        const { version, ...noVersion } = validPayload;
        expect(canvasJsonSchema.safeParse(noVersion).success).toBe(true);
    });

    it('accepts nodes with extra properties (passthrough)', () => {
        const payload = {
            ...validPayload,
            nodes: [{ id: 'n1', position: { x: 0, y: 0 }, data: {}, width: 200, height: 100, customProp: true }],
        };
        expect(canvasJsonSchema.safeParse(payload).success).toBe(true);
    });

    it('accepts edges with extra properties (passthrough)', () => {
        const payload = {
            ...validPayload,
            edges: [{ id: 'e1', source: 'n1', target: 'n2', type: 'step', animated: true }],
        };
        expect(canvasJsonSchema.safeParse(payload).success).toBe(true);
    });

    it('defaults missing title to "Untitled"', () => {
        const { title, ...noTitle } = validPayload;
        const result = canvasJsonSchema.safeParse(noTitle);
        expect(result.success).toBe(true);
        if (result.success) {
            expect(result.data.title).toBe('Untitled');
        }
    });

    it('rejects missing nodes', () => {
        const { nodes, ...noNodes } = validPayload;
        expect(canvasJsonSchema.safeParse(noNodes).success).toBe(false);
    });

    it('rejects missing edges', () => {
        const { edges, ...noEdges } = validPayload;
        expect(canvasJsonSchema.safeParse(noEdges).success).toBe(false);
    });

    it('rejects missing exportedAt', () => {
        const { exportedAt, ...noDate } = validPayload;
        expect(canvasJsonSchema.safeParse(noDate).success).toBe(false);
    });

    it('rejects nodes without id', () => {
        const payload = {
            ...validPayload,
            nodes: [{ position: { x: 0, y: 0 }, data: {} }],
        };
        expect(canvasJsonSchema.safeParse(payload).success).toBe(false);
    });

    it('rejects nodes without position', () => {
        const payload = {
            ...validPayload,
            nodes: [{ id: 'n1', data: {} }],
        };
        expect(canvasJsonSchema.safeParse(payload).success).toBe(false);
    });

    it('rejects edges without source', () => {
        const payload = {
            ...validPayload,
            edges: [{ id: 'e1', target: 'n2' }],
        };
        expect(canvasJsonSchema.safeParse(payload).success).toBe(false);
    });

    it('rejects edges without target', () => {
        const payload = {
            ...validPayload,
            edges: [{ id: 'e1', source: 'n1' }],
        };
        expect(canvasJsonSchema.safeParse(payload).success).toBe(false);
    });

    it('accepts empty nodes and edges arrays', () => {
        const payload = { ...validPayload, nodes: [], edges: [] };
        expect(canvasJsonSchema.safeParse(payload).success).toBe(true);
    });
});

// ─── importFromJson ──────────────────────────────────────────────────

describe('importFromJson', () => {
    function makeFile(content: string, name = 'canvas.json'): File {
        return new File([content], name, { type: 'application/json' });
    }

    const validJson = JSON.stringify({
        title: 'Test',
        nodes: [{ id: 'n1', position: { x: 0, y: 0 }, data: { label: 'Node' } }],
        edges: [{ id: 'e1', source: 'n1', target: 'n1' }],
        exportedAt: '2026-01-01T00:00:00Z',
    });

    it('parses a valid JSON file and returns nodes + edges', async () => {
        const result = await importFromJson(makeFile(validJson));
        expect(result.nodes).toHaveLength(1);
        expect(result.edges).toHaveLength(1);
        expect(result.nodes[0].id).toBe('n1');
    });

    it('throws on invalid JSON syntax', async () => {
        await expect(importFromJson(makeFile('{ not valid json }}')))
            .rejects.toThrow('Invalid JSON file');
    });

    it('throws on missing required fields', async () => {
        const noNodes = JSON.stringify({ title: 'Test', edges: [], exportedAt: '2026-01-01T00:00:00Z' });
        await expect(importFromJson(makeFile(noNodes)))
            .rejects.toThrow('Invalid canvas file');
    });

    it('throws on non-object input', async () => {
        await expect(importFromJson(makeFile('"just a string"')))
            .rejects.toThrow('Invalid canvas file');
    });

    it('throws on array input', async () => {
        await expect(importFromJson(makeFile('[1,2,3]')))
            .rejects.toThrow('Invalid canvas file');
    });

    it('preserves extra node properties', async () => {
        const json = JSON.stringify({
            title: 'Test',
            nodes: [{ id: 'n1', position: { x: 0, y: 0 }, data: {}, customField: 'hello' }],
            edges: [],
            exportedAt: '2026-01-01T00:00:00Z',
        });
        const result = await importFromJson(makeFile(json));
        expect(result.nodes[0].customField).toBe('hello');
    });
});

