import { WorkspaceDatabaseStorage } from '@server/modules/workspace/storage';
import { db } from '@server/modules/workspace/db';

describe('WorkspaceDatabaseStorage (Unit)', () => {
  let storage: WorkspaceDatabaseStorage;

  beforeEach(() => {
    storage = new WorkspaceDatabaseStorage();
    vi.clearAllMocks();
  });

  describe('updateWorkspace', () => {
    it('should call db.update with the correct id and updates', async () => {
      const mockWorkspace = {
        id: 1,
        title: 'Updated Title',
        type: 'system',
        icon: 'box',
        isFavorite: true,
        userId: 'user-123',
        collectionId: null,
        createdAt: new Date(),
      };

      const returningMock = vi.fn().mockResolvedValue([mockWorkspace]);
      const whereMock = vi.fn().mockReturnValue({ returning: returningMock });
      const setMock = vi.fn().mockReturnValue({ where: whereMock });
      (db.update as any).mockReturnValue({ set: setMock });

      const result = await storage.updateWorkspace(1, { isFavorite: true });

      expect(db.update).toHaveBeenCalled();
      expect(setMock).toHaveBeenCalledWith({ isFavorite: true, updatedAt: expect.any(Date) });
      expect(result).toEqual(mockWorkspace);
      expect(result.isFavorite).toBe(true);
    });

    it('should toggle isFavorite from true to false', async () => {
      const mockWorkspace = {
        id: 2,
        title: 'My Project',
        type: 'system',
        icon: 'server',
        isFavorite: false,
        userId: 'user-123',
        collectionId: null,
        createdAt: new Date(),
      };

      const returningMock = vi.fn().mockResolvedValue([mockWorkspace]);
      const whereMock = vi.fn().mockReturnValue({ returning: returningMock });
      const setMock = vi.fn().mockReturnValue({ where: whereMock });
      (db.update as any).mockReturnValue({ set: setMock });

      const result = await storage.updateWorkspace(2, { isFavorite: false });

      expect(setMock).toHaveBeenCalledWith({ isFavorite: false, updatedAt: expect.any(Date) });
      expect(result.isFavorite).toBe(false);
    });

    it('should update title without affecting isFavorite', async () => {
      const mockWorkspace = {
        id: 3,
        title: 'New Name',
        type: 'system',
        icon: 'box',
        isFavorite: true,
        userId: 'user-123',
        collectionId: null,
        createdAt: new Date(),
      };

      const returningMock = vi.fn().mockResolvedValue([mockWorkspace]);
      const whereMock = vi.fn().mockReturnValue({ returning: returningMock });
      const setMock = vi.fn().mockReturnValue({ where: whereMock });
      (db.update as any).mockReturnValue({ set: setMock });

      const result = await storage.updateWorkspace(3, { title: 'New Name' });

      expect(setMock).toHaveBeenCalledWith({ title: 'New Name', updatedAt: expect.any(Date) });
      expect(result.isFavorite).toBe(true); // preserved
    });
  });

  describe('duplicateWorkspace', () => {
    it('should create a copy with a new title', async () => {
      const original = {
        id: 1,
        title: 'Original',
        type: 'system',
        icon: 'cpu',
        isFavorite: true,
        userId: 'user-1',
        collectionId: null,
        createdAt: new Date(),
      };

      const duplicated = { ...original, id: 2, title: 'Original (Copy)', isFavorite: false };

      // Mock getWorkspace (select().from().where() must return iterable)
      const selectWhere = vi.fn().mockResolvedValue([original]);
      const selectFrom = vi.fn().mockReturnValue({ where: selectWhere });
      (db.select as any).mockReturnValue({ from: selectFrom });

      // Mock insert
      const insertReturning = vi.fn().mockResolvedValue([duplicated]);
      const insertValues = vi.fn().mockReturnValue({ returning: insertReturning });
      (db.insert as any).mockReturnValue({ values: insertValues });

      const result = await storage.duplicateWorkspace(1, 'Original (Copy)');

      expect(result.title).toBe('Original (Copy)');
      expect(result.id).not.toBe(original.id);
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
    SHORTCUTS,
    SHORTCUT_CATEGORIES,
    getShortcutsByCategory,
    type ShortcutDefinition,
} from '@/features/workspace/utils/shortcuts';

describe('Keyboard Shortcuts', () => {

    // ─── Data integrity ────────────────────────────────────────────

    it('has at least 10 shortcuts defined', () => {
        expect(SHORTCUTS.length).toBeGreaterThanOrEqual(10);
    });

    it('has no duplicate key combos', () => {
        const keys = SHORTCUTS.map(s => s.key);
        const unique = new Set(keys);
        expect(unique.size).toBe(keys.length);
    });

    it('has no duplicate labels', () => {
        const labels = SHORTCUTS.map(s => s.label);
        const unique = new Set(labels);
        expect(unique.size).toBe(labels.length);
    });

    it('every shortcut has a non-empty key', () => {
        SHORTCUTS.forEach(s => {
            expect(s.key.trim().length).toBeGreaterThan(0);
        });
    });

    it('every shortcut has a non-empty label', () => {
        SHORTCUTS.forEach(s => {
            expect(s.label.trim().length).toBeGreaterThan(0);
        });
    });

    it('every shortcut belongs to a valid category', () => {
        SHORTCUTS.forEach(s => {
            expect(SHORTCUT_CATEGORIES).toContain(s.category);
        });
    });

    // ─── Category definitions ──────────────────────────────────────

    it('has exactly 4 categories', () => {
        expect(SHORTCUT_CATEGORIES).toHaveLength(4);
    });

    it('includes Navigation, Editing, Canvas, View', () => {
        expect(SHORTCUT_CATEGORIES).toContain('Navigation');
        expect(SHORTCUT_CATEGORIES).toContain('Editing');
        expect(SHORTCUT_CATEGORIES).toContain('Canvas');
        expect(SHORTCUT_CATEGORIES).toContain('View');
    });

    // ─── Grouping ──────────────────────────────────────────────────

    it('getShortcutsByCategory returns all categories', () => {
        const grouped = getShortcutsByCategory();
        for (const cat of SHORTCUT_CATEGORIES) {
            expect(grouped[cat]).toBeDefined();
            expect(Array.isArray(grouped[cat])).toBe(true);
        }
    });

    it('grouped shortcuts total matches SHORTCUTS length', () => {
        const grouped = getShortcutsByCategory();
        const total = Object.values(grouped).reduce((sum, arr) => sum + arr.length, 0);
        expect(total).toBe(SHORTCUTS.length);
    });

    it('each category has at least 2 shortcuts', () => {
        const grouped = getShortcutsByCategory();
        for (const cat of SHORTCUT_CATEGORIES) {
            expect(grouped[cat].length).toBeGreaterThanOrEqual(2);
        }
    });

    // ─── Specific key mappings ─────────────────────────────────────

    it('? key is mapped to show shortcuts', () => {
        const found = SHORTCUTS.find(s => s.key === '?');
        expect(found).toBeDefined();
        expect(found!.label.toLowerCase()).toContain('shortcut');
    });

    it('F11 is mapped to fullscreen', () => {
        const found = SHORTCUTS.find(s => s.key === 'F11');
        expect(found).toBeDefined();
        expect(found!.label.toLowerCase()).toContain('fullscreen');
    });

    it('Ctrl+Z is mapped to undo', () => {
        const found = SHORTCUTS.find(s => s.key === 'Ctrl+Z');
        expect(found).toBeDefined();
        expect(found!.label.toLowerCase()).toContain('undo');
    });

    it('Ctrl+S is mapped to save', () => {
        const found = SHORTCUTS.find(s => s.key === 'Ctrl+S');
        expect(found).toBeDefined();
        expect(found!.label.toLowerCase()).toContain('save');
    });
});
